# Split the content into objects
# Since parsing the whole thing as JSON is hard, we can use regex to replace specific objects by their names
for index, new_data in new_cards.items():
    name = new_data["name"]
    # Find the object starting with "name": "name"
    pattern = r'\{[^{}]*"name": "' + name + r'"[^{}]*\}'
    
    # Format the new object string
    new_obj_str = "{\n"
    for key, value in new_data.items():
        if isinstance(value, list):
            val_str = json.dumps(value, ensure_ascii=False)
        else:
            val_str = json.dumps(value, ensure_ascii=False)
        new_obj_str += f'    "{key}": {val_str},\n'
    
    # Remove the last comma and close
    new_obj_str = new_obj_str.rstrip(",\n") + "\n  }"
    
    # We need to be careful with the replacement to not break the comma after the object if it exists
    # Find the object and replace it
    search_pattern = r'\{\s*"name": "' + name + r'".*?\}'
    content = re.sub(search_pattern, new_obj_str, content, flags=re.DOTALL)

with open(file_path, "w", encoding="utf-8") as f:
    f.write(content)

